'use client';

import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useEffect, useRef, useState } from 'react';
import { BaseArticle } from '@/types/article.types';
import { Category } from '@/types/category.types';
import Heading from '@/components/ui/Heading';
import { ChevronRightIcon } from '@/components/common/Icons';
import ImageWithSkeleton from '@/components/common/ImageWithSkeleton';

interface ArticleFeedByCategoryClientProps {
	category: Category;
	categoryArticles: BaseArticle[];
}

const ArticleFeedByCategoryClient = ({
	category,
	categoryArticles,
}: ArticleFeedByCategoryClientProps) => {
	const router = useRouter();
	const elementRef = useRef<HTMLDivElement | null>(null);
	const [isVisible, setIsVisible] = useState(false);

	useEffect(() => {
		const observer = new IntersectionObserver(
			([entry]) => {
				if (entry.isIntersecting) {
					setIsVisible(true);
					observer.disconnect();
				}
			},
			{
				threshold: 0.1,
				rootMargin: '10px',
			},
		);

		if (elementRef.current) {
			observer.observe(elementRef.current);
		}

		return () => observer.disconnect();
	}, []);

	return (
		<div ref={elementRef} className='w-full'>
			<div className='flex justify-between items-start mb-4'>
				<Heading title={category.name} size='sm' />
				{categoryArticles.length >= 4 && (
					<button
						className='flex gap-0.25 py-0.75 items-center justify-center hover:text-primary transition break'
						onClick={() => router.push(`/news/topics/${category.slug}`)}
						aria-label={`View ${category.name} articles`}
					>
						<span className='text-xs'>View</span>
						<ChevronRightIcon size={14} />
					</button>
				)}
			</div>

			{/* {!isVisible && (
				<div className='flex flex-col gap-3 animate-pulse'>
					<div className='h-40 bg-gray-300 rounded'></div>
					<div className='h-4 bg-gray-300 rounded w-3/4'></div>
				</div>
			)} */}

			<div className='flex flex-col gap-3 '>
				<Link
					href={`/news/articles/${categoryArticles[0].slug}`}
					key={categoryArticles[0].id}
					className='flex flex-col gap-2 rounded transition-all duration-150 ease-in-out group'
					aria-label={`view ${categoryArticles[0].title} article`}
				>
					{categoryArticles[0].banner_image && (
						<ImageWithSkeleton
							src={categoryArticles[0].banner_image}
							alt={categoryArticles[0].title}
							parentClassName='w-full h-[200px] sm:max-w-[250px] lg:max-w-[300px]'
						/>
					)}
					<h2 className='text-[13px] font-medium w-full sm:max-w-[300px] mt-3 group-hover:text-primary transition'>
						{categoryArticles[0].title}
					</h2>
				</Link>

				{categoryArticles.slice(1, 4).map((article) => (
					<Link
						href={`/news/articles/${article.slug}`}
						key={article.id}
						className='flex flex-col gap-1 rounded hover:text-primary border-t border-gray-300 transition-all duration-150 ease-in-out'
						aria-label={`view ${article.title} article`}
					>
						<h2 className='text-[13px] font-medium w-full sm:max-w-[300px] mt-2'>
							{article.title}
						</h2>
					</Link>
				))}
			</div>
		</div>
	);
};

export default ArticleFeedByCategoryClient;
